/** Petshop Probe Slot v11 (Exclusion price+cost audit) */
add_action('wp_loaded', function(){
  if ( ($_GET['ps_probe'] ?? '') !== 'ps2026' ) return;
  global $wpdb;
  $out = array('ts'=>gmdate('c'));
  $ids = $wpdb->get_col("SELECT ID FROM {$wpdb->posts} WHERE post_type='product' AND post_status IN('publish','draft') AND post_title LIKE '%xclusion%' ORDER BY post_title LIMIT 120");
  $out['count'] = count($ids);
  $rows = array();
  $keys = array('_sku','_regular_price','_sale_price','_price','_cost_price','_vf_price','_vf_cost','_vf_qty','_zb_cost','_legacy_cost','_active_fulfillment_source','_manual_price_override');
  foreach($ids as $i=>$id){
    $r = array('id'=>$id, 't'=>mb_substr(get_the_title($id),0,70), 'st'=>get_post_status($id));
    foreach($keys as $k){ $v = get_post_meta($id,$k,true); if($v!=='') $r[ltrim($k,'_')]=$v; }
    $rows[] = $r;
  }
  $out['rows'] = $rows;
  // pirmo produkto visi meta raktai su price/cost/vf
  if($ids){
    $mk = $wpdb->get_results($wpdb->prepare("SELECT meta_key, meta_value FROM {$wpdb->postmeta} WHERE post_id=%d AND (meta_key LIKE '%%cost%%' OR meta_key LIKE '%%price%%' OR meta_key LIKE '%%vf%%')", $ids[0]), ARRAY_A);
    $out['sample_meta'] = $mk;
  }
  header('Content-Type: application/json');
  echo wp_json_encode($out);
  exit;
}, 1);
